1	import { readFile, writeFile } from "node:fs/promises";
2	import type {
3	  CommentId,
4	  ComputedComment,
5	  ComputedIssue,
6	  Event,
7	  IssueId,
8	  IssueStatus,
9	  UpdateEvent,
10	} from "../types";
11	
12	/**
13	 * Append a single event to an issue's JSON file (array of events).
14	 * Creates the file with a JSON array if it doesn't exist yet.
15	 */
16	export async function appendEvent(issuePath: string, event: Event): Promise<void> {
17	  let events: Event[];
18	
19	  try {
20	    const contents = await readFile(issuePath, "utf-8");
21	    events = JSON.parse(contents) as Event[];
22	  } catch {
23	    events = [];
24	  }
25	
26	  events.push(event);
27	  await writeFile(issuePath, `${JSON.stringify(events, null, 2)}\n`, "utf-8");
28	}
29	
30	/**
31	 * Read an issue file and return the raw event array.
32	 */
33	export async function replayEvents(issuePath: string): Promise<Event[]> {
34	  const contents = await readFile(issuePath, "utf-8");
35	  return JSON.parse(contents) as Event[];
36	}
37	
38	/** Default values for a new issue (no events applied yet). */
39	const DEFAULTS = {
40	  status: "idea" as IssueStatus,
41	  priority: 3 as 1 | 2 | 3 | 4 | 5,
42	  assignee: null as string | null,
43	  parentId: null as string | null,
44	  tags: [] as string[],
45	  description: "",
46	};
47	
48	/** Mutable state being built during event replay. */
49	interface IssueState {
50	  title: string;
51	  description: string;
52	  status: IssueStatus;
53	  priority: 1 | 2 | 3 | 4 | 5;
54	  assignee: string | null;
55	  parentId: string | null;
56	  tags: string[];
57	}
58	
59	/**
60	 * Apply an update event's content to the mutable state.
61	 */
62	function applyUpdate(state: IssueState, content: UpdateEvent["content"]): void {
63	  if (content.title !== undefined) state.title = content.title;
64	  if (content.description !== undefined) state.description = content.description;
65	  if (content.status !== undefined) state.status = content.status;
66	  if (content.priority !== undefined) state.priority = content.priority;
67	  if (content.assignee !== undefined) state.assignee = content.assignee;
68	  if (content.parentId !== undefined) state.parentId = content.parentId;
69	  if (content.tags !== undefined) state.tags = content.tags;
70	}
71	
72	/**
73	 * Replay events to produce a ComputedIssue.
74	 *
75	 * - Creation event: sets createdAt, createdBy.
76	 * - Update events: merge content fields into properties.
77	 * - Comment / blockage events: ignored (handled separately).
78	 * - updatedAt = timestamp of last event.
79	 *
80	 * The `id` comes from the filename, not from the events.
81	 */
82	export function computeState(events: Event[], issueId: IssueId): ComputedIssue {
83	  const state: IssueState = {
84	    title: "",
85	    description: DEFAULTS.description,
86	    status: DEFAULTS.status,
87	    priority: DEFAULTS.priority,
88	    assignee: DEFAULTS.assignee,
89	    parentId: DEFAULTS.parentId,
90	    tags: [...DEFAULTS.tags],
91	  };
92	
93	  let createdAt = "";
94	  let createdBy = "";
95	  let updatedAt = "";
96	
97	  for (const event of events) {
98	    updatedAt = event.timestamp;
99	
100	    if (event.type === "creation") {
101	      createdAt = event.timestamp;
102	      createdBy = event.author;
103	    } else if (event.type === "update") {
104	      applyUpdate(state, event.content);
105	    }
106	    // Comment and blockage events are metadata-only — skip
107	  }
108	
109	  return {
110	    id: issueId,
111	    ...state,
112	    createdAt,
113	    createdBy,
114	    updatedAt,
115	  };
116	}
117	
118	/**
119	 * Replay events to compute the current list of comments.
120	 *
121	 * - `comment` event → create new entry
122	 * - `comment-update` event → update content and editedAt (skip if missing/deleted)
123	 * - `comment-delete` event → remove entry from the map
124	 * - All other event types are ignored.
125	 *
126	 * Returns comments sorted by creation timestamp ascending.
127	 */
128	export function computeComments(events: Event[]): ComputedComment[] {
129	  const map = new Map<CommentId, ComputedComment>();
130	
131	  for (const event of events) {
132	    if (event.type === "comment") {
133	      map.set(event.content.id, {
134	        id: event.content.id,
135	        author: event.author,
136	        content: event.content.content,
137	        timestamp: event.timestamp,
138	        editedAt: null,
139	      });
140	    } else if (event.type === "comment-update") {
141	      const existing = map.get(event.content.id);
142	      if (existing) {
143	        existing.content = event.content.content;
144	        existing.editedAt = event.timestamp;
145	      }
146	    } else if (event.type === "comment-delete") {
147	      map.delete(event.content.id);
148	    }
149	    // All other event types are ignored
150	  }
151	
152	  return Array.from(map.values()).sort((a, b) =>
153	    a.timestamp < b.timestamp ? -1 : a.timestamp > b.timestamp ? 1 : 0,
154	  );
155	}
