1	import { TrackgenticError } from "../../core/errors";
2	import { Tracker } from "../../core/tracker";
3	import { writeStderr, writeStdout } from "../output";
4	
5	/**
6	 * Handler for the `trackgentic comments add <issueId> --content <content>` command.
7	 */
8	export async function commentsAddAction(
9	  issueId: string,
10	  options: { content: string },
11	): Promise<void> {
12	  try {
13	    const tracker = new Tracker();
14	    const result = await tracker.commentsAdd(issueId, { content: options.content });
15	    if (result instanceof TrackgenticError) {
16	      writeStderr({ result: result.result, message: result.message });
17	      process.exit(result.exitCode);
18	    }
19	    writeStdout(result);
20	    process.exit(0);
21	  } catch (err) {
22	    if (err instanceof TrackgenticError) {
23	      writeStderr({ result: err.result, message: err.message });
24	      process.exit(err.exitCode);
25	    }
26	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
27	    process.exit(1);
28	  }
29	}
