1	import { existsSync, mkdirSync } from "node:fs";
2	import { join, resolve } from "node:path";
3	import type {
4	  CommentAddParams,
5	  CommentAddResult,
6	  CommentDeleteParams,
7	  CommentDeleteResult,
8	  CommentsListResult,
9	  CommentUpdateParams,
10	  CommentUpdateResult,
11	  ConfigFile,
12	  CreateParams,
13	  CreateResult,
14	  DependenciesFile,
15	  HistoryResult,
16	  IndexEntry,
17	  IndexFile,
18	  InitResult,
19	  IssueId,
20	  IssueProperties,
21	  IssueStatus,
22	  ListParams,
23	  ListResult,
24	  UpdateParams,
25	  UpdateResult,
26	  UserEntry,
27	  UsersFile,
28	  UsersListResult,
29	  UsersRegenerateResult,
30	  UsersRegisterResult,
31	  UsersRevokeResult,
32	  ViewResult,
33	} from "../types";
34	import { resolveAuthor } from "./auth";
35	import { ErrorCodes, TrackgenticError } from "./errors";
36	import { appendEvent, computeComments, computeState, replayEvents } from "./events";
37	import { atomicWriteJSON, readJSON } from "./file-io";
38	import { generateCommentId, generateId } from "./id";
39	import { findEntry, insertEntry, readIndex, updateEntry, writeIndex } from "./index-manager";
40	import { resolveTrackerDir } from "./resolution";
41	
42	const TRACKGENTIC_DIR = ".trackgentic";
43	
44	/**
45	 * Default config.json contents.
46	 */
47	const DEFAULT_CONFIG: ConfigFile = {
48	  auth: {
49	    mode: "open",
50	    defaultUser: "anonymous",
51	  },
52	};
53	
54	/**
55	 * Default index.json contents.
56	 */
57	const DEFAULT_INDEX: IndexFile = {
58	  open: [],
59	  closed: [],
60	  childrenOf: {},
61	};
62	
63	/**
64	 * Default dependencies.json contents.
65	 */
66	const DEFAULT_DEPENDENCIES: DependenciesFile = {
67	  blockedBy: {},
68	  blocks: {},
69	};
70	
71	/**
72	 * Default users.json contents.
73	 */
74	const DEFAULT_USERS: UsersFile = {
75	  users: [],
76	};
77	
78	/**
79	 * Generate a token: tk_ + 8 random alphanumeric characters.
80	 */
81	function generateToken(): string {
82	  return `tk_${Math.random().toString(36).slice(2, 10)}`;
83	}
84	
85	/**
86	 * Tracker — the main programmatic API for trackgentic.
87	 *
88	 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
89	 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
90	 */
91	export class Tracker {
92	  private cwd: string;
93	
94	  constructor(cwd?: string) {
95	    this.cwd = cwd ?? process.cwd();
96	  }
97	
98	  /**
99	   * Initialize a new `.trackgentic/` directory in `cwd`.
100	   */
101	  async init(): Promise<InitResult> {
102	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
103	
104	    if (existsSync(trackerDir)) {
105	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
106	    }
107	
108	    mkdirSync(trackerDir, { recursive: true });
109	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
110	
111	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
112	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
113	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
114	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
115	
116	    return { result: "OK", path: resolve(trackerDir) };
117	  }
118	
119	  /**
120	   * Create a new issue.
121	   */
122	  async create(params: CreateParams): Promise<CreateResult> {
123	    const trackerDir = resolveTrackerDir(this.cwd);
124	    if (!trackerDir) {
125	      throw new TrackgenticError(
126	        ErrorCodes.NOT_INITIALIZED.result,
127	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
128	        ErrorCodes.NOT_INITIALIZED.exitCode,
129	      );
130	    }
131	
132	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
133	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
134	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
135	    if (authResult instanceof TrackgenticError) return authResult;
136	    const author = params.author ?? authResult.author;
137	
138	    const id = generateId();
139	    const issuePath = params.path ?? `issues/${id}.json`;
140	    const now = new Date().toISOString();
141	
142	    const title = params.title;
143	    const description = params.description ?? "";
144	    const status: IssueStatus = params.status ?? "idea";
145	    const priority = params.priority ?? 3;
146	    const assignee = params.assignee ?? null;
147	    const parentId = params.parentId ?? null;
148	    const tags = params.tags ?? [];
149	
150	    // Build update content with only non-default values
151	    const updateContent: Partial<
152	      Pick<
153	        IssueProperties,
154	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
155	      >
156	    > & { title: string } = { title };
157	    if (description) updateContent.description = description;
158	    if (status !== "idea") updateContent.status = status;
159	    if (priority !== 3) updateContent.priority = priority;
160	    if (assignee !== null) updateContent.assignee = assignee;
161	    if (parentId !== null) updateContent.parentId = parentId;
162	    if (tags.length > 0) updateContent.tags = tags;
163	
164	    // Create issue file with two events: creation + update
165	    const creationEvent = { type: "creation" as const, timestamp: now, author };
166	    const updateEvent = {
167	      type: "update" as const,
168	      timestamp: now,
169	      author,
170	      content: updateContent,
171	    };
172	
173	    const issueFilePath = join(trackerDir, issuePath);
174	    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);
175	
176	    // Build index entry and insert into index
177	    const entry: IndexEntry = {
178	      id,
179	      title,
180	      path: issuePath,
181	      status,
182	      assignee,
183	      parentId,
184	      tags,
185	      priority,
186	    };
187	
188	    const index = await readIndex(trackerDir);
189	    const updatedIndex = insertEntry(index, entry);
190	    await writeIndex(trackerDir, updatedIndex);
191	
192	    return { id };
193	  }
194	
195	  /**
196	   * List issues from the index, with optional filters.
197	   */
198	  async list(params?: ListParams): Promise<ListResult> {
199	    const trackerDir = resolveTrackerDir(this.cwd);
200	    if (!trackerDir) {
201	      throw new TrackgenticError(
202	        ErrorCodes.NOT_INITIALIZED.result,
203	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
204	        ErrorCodes.NOT_INITIALIZED.exitCode,
205	      );
206	    }
207	
208	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
209	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
210	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
211	    if (authResult instanceof TrackgenticError) {
212	      throw authResult;
213	    }
214	
215	    const index = await readIndex(trackerDir);
216	
217	    // Determine source arrays based on params.status
218	    let entries: IndexEntry[];
219	    if (params?.status === "closed") {
220	      entries = index.closed;
221	    } else if (params?.status === "open") {
222	      entries = index.open;
223	    } else if (params?.status) {
224	      entries = index.open;
225	    } else {
226	      entries = [...index.open, ...index.closed];
227	    }
228	
229	    // Filter in memory
230	    let filtered = entries;
231	
232	    if (params?.status && params.status !== "open" && params.status !== "closed") {
233	      filtered = filtered.filter((e) => e.status === params.status);
234	    }
235	
236	    if (params?.assignee) {
237	      filtered = filtered.filter((e) => e.assignee === params.assignee);
238	    }
239	
240	    if (params?.tags && params.tags.length > 0) {
241	      filtered = filtered.filter((e) => params.tags?.every((tag) => e.tags.includes(tag)));
242	    }
243	
244	    if (params?.parentId !== undefined) {
245	      if (params.parentId === null) {
246	        filtered = filtered.filter((e) => e.parentId === null);
247	      } else {
248	        filtered = filtered.filter((e) => e.parentId === params.parentId);
249	      }
250	    }
251	
252	    // Sort: priority ASC → id ASC
253	    filtered.sort((a, b) => {
254	      if (a.priority !== b.priority) return a.priority - b.priority;
255	      return a.id.localeCompare(b.id);
256	    });
257	
258	    return filtered;
259	  }
260	
261	  /**
262	   * View a single issue's full computed state.
263	   */
264	  async view(id: IssueId): Promise<ViewResult> {
265	    const trackerDir = resolveTrackerDir(this.cwd);
266	    if (!trackerDir) {
267	      throw new TrackgenticError(
268	        ErrorCodes.NOT_INITIALIZED.result,
269	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
270	        ErrorCodes.NOT_INITIALIZED.exitCode,
271	      );
272	    }
273	
274	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
275	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
276	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
277	    if (authResult instanceof TrackgenticError) {
278	      throw authResult;
279	    }
280	
281	    const index = await readIndex(trackerDir);
282	    const entry = findEntry(index, id);
283	    if (!entry) {
284	      throw new TrackgenticError(
285	        ErrorCodes.NOT_FOUND.result,
286	        `Issue ${id} not found in index.`,
287	        ErrorCodes.NOT_FOUND.exitCode,
288	      );
289	    }
290	
291	    const issueFilePath = join(trackerDir, entry.path);
292	    if (!existsSync(issueFilePath)) {
293	      throw new TrackgenticError(
294	        ErrorCodes.ISSUE_MISSING.result,
295	        `Issue file for ${id} is missing.`,
296	        ErrorCodes.ISSUE_MISSING.exitCode,
297	      );
298	    }
299	
300	    const events = await replayEvents(issueFilePath);
301	    return computeState(events, id);
302	  }
303	
304	  /**
305	   * Update an existing issue.
306	   */
307	  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
308	    const trackerDir = resolveTrackerDir(this.cwd);
309	    if (!trackerDir) {
310	      throw new TrackgenticError(
311	        ErrorCodes.NOT_INITIALIZED.result,
312	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
313	        ErrorCodes.NOT_INITIALIZED.exitCode,
314	      );
315	    }
316	
317	    // Validate at least one field provided (besides author)
318	    const hasField =
319	      params.title !== undefined ||
320	      params.description !== undefined ||
321	      params.status !== undefined ||
322	      params.assignee !== undefined ||
323	      params.tags !== undefined ||
324	      params.priority !== undefined ||
325	      params.parentId !== undefined;
326	
327	    if (!hasField) {
328	      throw new TrackgenticError(
329	        ErrorCodes.INVALID_PARAMS.result,
330	        "At least one field must be provided for update.",
331	        ErrorCodes.INVALID_PARAMS.exitCode,
332	      );
333	    }
334	
335	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
336	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
337	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
338	    if (authResult instanceof TrackgenticError) return authResult;
339	    const author = params.author ?? authResult.author;
340	
341	    const index = await readIndex(trackerDir);
342	    const entry = findEntry(index, id);
343	    if (!entry) {
344	      throw new TrackgenticError(
345	        ErrorCodes.NOT_FOUND.result,
346	        `Issue ${id} not found in index.`,
347	        ErrorCodes.NOT_FOUND.exitCode,
348	      );
349	    }
350	
351	    const issueFilePath = join(trackerDir, entry.path);
352	    if (!existsSync(issueFilePath)) {
353	      throw new TrackgenticError(
354	        ErrorCodes.ISSUE_MISSING.result,
355	        `Issue file for ${id} is missing.`,
356	        ErrorCodes.ISSUE_MISSING.exitCode,
357	      );
358	    }
359	
360	    // Build update event content with only the provided fields
361	    const content: Partial<
362	      Pick<
363	        IssueProperties,
364	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
365	      >
366	    > = {};
367	    if (params.title !== undefined) content.title = params.title;
368	    if (params.description !== undefined) content.description = params.description;
369	    if (params.status !== undefined) content.status = params.status;
370	    if (params.assignee !== undefined) content.assignee = params.assignee;
371	    if (params.tags !== undefined) content.tags = params.tags;
372	    if (params.priority !== undefined) content.priority = params.priority;
373	    if (params.parentId !== undefined) content.parentId = params.parentId;
374	
375	    const now = new Date().toISOString();
376	
377	    const updateEvent = {
378	      type: "update" as const,
379	      timestamp: now,
380	      author,
381	      content,
382	    };
383	
384	    // Append event to issue file
385	    await appendEvent(issueFilePath, updateEvent);
386	
387	    // Recompute state from all events
388	    const events = await replayEvents(issueFilePath);
389	    const computed = computeState(events, id);
390	
391	    // Update index entry with new computed values
392	    const updatedIndex = updateEntry(index, id, {
393	      title: computed.title,
394	      status: computed.status,
395	      assignee: computed.assignee,
396	      parentId: computed.parentId,
397	      tags: computed.tags,
398	      priority: computed.priority,
399	    });
400	
401	    await writeIndex(trackerDir, updatedIndex);
402	
403	    return { result: "OK" };
404	  }
405	
406	  /**
407	   * Get the raw event history for an issue.
408	   */
409	  async history(id: IssueId): Promise<HistoryResult> {
410	    const trackerDir = resolveTrackerDir(this.cwd);
411	    if (!trackerDir) {
412	      throw new TrackgenticError(
413	        ErrorCodes.NOT_INITIALIZED.result,
414	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
415	        ErrorCodes.NOT_INITIALIZED.exitCode,
416	      );
417	    }
418	
419	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
420	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
