792	  async usersRegenerate(name: string): Promise<UsersRegenerateResult> {
793	    const trackerDir = resolveTrackerDir(this.cwd);
794	    if (!trackerDir) {
795	      throw new TrackgenticError(
796	        ErrorCodes.NOT_INITIALIZED.result,
