799	      );
800	    }
801	
802	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
803	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
804	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
805	    if (authResult instanceof TrackgenticError) {
806	      throw authResult;
807	    }
808	
809	    const callerName = authResult.author;
810	    const lowerName = name.toLowerCase();
811	
812	    // Self-service check: caller must be the target user
813	    if (callerName !== lowerName) {
814	      return {
815	        result: "INVALID_TOKEN",
816	        message: `You can only regenerate your own token.`,
817	      };
818	    }
819	
820	    const user = users.users.find((u) => u.name === lowerName);
821	    if (!user) {
822	      return {
823	        result: "USER_NOT_FOUND",
824	        message: `User "${lowerName}" not found.`,
825	      };
826	    }
827	
828	    const newToken = generateToken();
829	    user.token = newToken;
830	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
831	
832	    return { result: "OK", name: lowerName, token: newToken };
833	  }
